python3 << 'EOF'
import json
import os
from pathlib import Path

models_dir = "/home/nick/work/AutoIREE/models"

# Scan different models for record structures
record_stats = {}

for model_dir in Path(models_dir).glob("*/*/record/*/"):
    history_log = model_dir / "history.log"
    if history_log.exists():
        with open(history_log, 'r') as f:
            dispatches = set()
            entry_count = 0
            for line in f:
                if line.strip():
                    entry = json.loads(line)
                    dispatches.add(entry["input"][2])
                    entry_count += 1

        model_name = str(model_dir.parent.parent.name)
        if model_name not in record_stats:
            record_stats[model_name] = []
        record_stats[model_name].append({
            'record_dir': model_dir.name,
            'num_dispatches': len(dispatches),
            'num_entries': entry_count,
            'dispatches': sorted(list(dispatches))
        })

print("=== Record Structure Summary ===\n")
for model_name in sorted(record_stats.keys()):
    stats = record_stats[model_name]
    print(f"{model_name}:")
    for record in stats[:3]:  # Show first 3 records per model
        print(f"  {record['record_dir']}: {record['num_dispatches']} dispatch(es), {record['num_entries']} entries")
        if record['num_dispatches'] <= 3:
            for d in record['dispatches']:
                print(f"    - {d}")
    if len(stats) > 3:
        print(f"  ... and {len(stats) - 3} more record directories")
    print()
EOF

